// ════════════════════════════════════════════════
// CONFIGURAR PARA CADA LOJA
// ════════════════════════════════════════════════

const PANEL_ID          = "ddd69db3-e0e9-43dd-b7e9-caca39191f53";
const HELENA_TOKEN      = "pn_r2wckLvlRLYcVF0B3NwLfHTnRLuOzsiqOmx3BYqU0xE";
const STORE_EXTERNAL_ID = "loja-maringa";  // ID externo único por loja
const DASHBOARD_URL     = "https://fabricante-dashboard-production.up.railway.app";
const WEBHOOK_SECRET    = "pprrc1357";

// Mapeamento: UUID da etiqueta Helena → stepId do Kanban + dashKey do funil
// dashKey null = move o card no Kanban mas não registra no Dashboard
const STAGE_MAP = {
  // 01.Classificar → Lead Capturado
  "fa577cc1-538b-4865-ad28-47fe418e8a8f": { stepId: "bf520368-c720-4c5b-b978-dd82f8ca6c50", dashKey: "lead_capturado" },
  // 02.Qualificação → registra no Dashboard para calcular tempo de 1ª resposta
  "d7473602-9f4b-4f55-a5c5-9fa663f08c93": { stepId: "fbfa00b1-63b4-48b5-b47b-3dbb38694440", dashKey: "visita_agendada" },
  // 03.Visita agendada → Visita Técnica Agendada
  "d09d13f5-a4e2-4928-97e7-60cbb18375c6": { stepId: "0ed8c146-9325-479c-9227-225f3ac7d122", dashKey: "visita_agendada" },
  // 04.Visita Realizada → Visita Realizada
  "70aaebcf-bed7-41ae-ae7f-186b21f2448c": { stepId: "65396ec0-9ce9-46cb-aab0-d42889d4fea1", dashKey: "visita_realizada" },
  // 05.AG Orçamento → Elaboração de Projeto 3D
  "32677154-b3c1-4482-8d94-63f1ad5a0645": { stepId: "002c6571-bed1-4555-9db6-0005cb27ecda", dashKey: "projeto_3d" },
  // 06.Orçamento Enviado → Orçamento Enviado
  "a80b3729-729e-4bb0-b5d9-844127fff502": { stepId: "b212c8ef-83e2-43b2-9a19-387e85f19d61", dashKey: "orcamento_enviado" },
  // 07.Negociação → Em Negociação
  "8514d798-0207-4123-a0aa-30c0f8f0d9f4": { stepId: "5761cdb4-7bd6-47df-98fc-42afb7d8462c", dashKey: "negociacao" },
  // 08.AG Assinatura → Contrato Enviado
  "c51c7959-ad2a-4339-ac17-eb5741cb1e79": { stepId: "e37015b3-2c9b-45cc-8afb-6d021187a158", dashKey: "contrato_enviado" },
  // 09.1AG Pagamento → Aguardando Pagamento
  "c1f06360-048f-438a-bc63-96de6ad3f26e": { stepId: "5570c9bd-dfe9-43ca-aee0-54b884cbc61d", dashKey: "aguardando_pagamento" },
  // 09.3PG Aprovado → Pagamento Aprovado
  "d9c5a679-138e-4c0c-8eb0-5ce716f06bed": { stepId: "849d3636-a831-4ab9-bc33-0ef64d9a6d3c", dashKey: "pagamento_aprovado" },
  // 09.2Venda Perdida → só move no Kanban
  "bcb59f5f-a5bc-48be-b39e-29ad087bcae3": { stepId: "09ff3b51-5de1-4fd8-9e9b-ef001971bf5c", dashKey: null },
  // 10.Obra Futura → só move no Kanban
  "f6ce83fe-b490-40d2-b814-6e5058da9531": { stepId: "b5c3b82f-9ea8-4a32-b1bc-e29705ab6f9b", dashKey: null }
};

const STAGE_PRIORITY = [
  "d9c5a679-138e-4c0c-8eb0-5ce716f06bed",  // 09.3 PG Aprovado
  "bcb59f5f-a5bc-48be-b39e-29ad087bcae3",  // 09.2 Venda Perdida
  "f6ce83fe-b490-40d2-b814-6e5058da9531",  // 10. Obra Futura
  "c1f06360-048f-438a-bc63-96de6ad3f26e",  // 09.1 AG Pagamento
  "c51c7959-ad2a-4339-ac17-eb5741cb1e79",  // 08. AG Assinatura
  "8514d798-0207-4123-a0aa-30c0f8f0d9f4",  // 07. Negociação
  "a80b3729-729e-4bb0-b5d9-844127fff502",  // 06. Orçamento Enviado
  "32677154-b3c1-4482-8d94-63f1ad5a0645",  // 05. AG Orçamento
  "70aaebcf-bed7-41ae-ae7f-186b21f2448c",  // 04. Visita Realizada
  "d09d13f5-a4e2-4928-97e7-60cbb18375c6",  // 03. Visita agendada
  "d7473602-9f4b-4f55-a5c5-9fa663f08c93",  // 02. Qualificação
  "fa577cc1-538b-4865-ad28-47fe418e8a8f"   // 01. Classificar
];

// ════════════════════════════════════════════════
// LÓGICA (não alterar)
// ════════════════════════════════════════════════
const body = $input.first().json.body ?? $input.first().json;

if (body.eventType !== 'CONTACT_TAG_UPDATE') {
  return [{ json: { skip: true } }];
}

const tagsId    = body.content?.tagsId ?? [];
const contactId = body.content?.id;

if (!contactId) return [{ json: { skip: true } }];

const matched = tagsId.filter(t => STAGE_MAP[t]);
if (matched.length === 0) return [{ json: { skip: true } }];

const winner = STAGE_PRIORITY.find(s => matched.includes(s)) ?? matched[0];
const stage  = STAGE_MAP[winner];

return [{
  json: {
    skip:            false,
    contactId,
    stepId:          stage.stepId,
    dashKey:         stage.dashKey ?? null,
    sendToDash:      stage.dashKey !== null,
    panelId:         PANEL_ID,
    helenToken:      HELENA_TOKEN,
    storeExternalId: STORE_EXTERNAL_ID,
    dashboardUrl:    DASHBOARD_URL,
    webhookSecret:   WEBHOOK_SECRET,
    occurredAt:      body.date,
    eventId:         contactId + '-' + body.date
  }
}];

const ctx         = $('Determinar Etapa').first().json;
const cardResp    = $('Buscar Card').first().json;
const contactResp = $('Buscar Contato').first().json;
const agentsResp  = $input.first().json;

let cardId         = null;
let cardFound      = false;
let agentEmail     = null;
let agentName      = null;
let contactName    = null;
let contactPhone   = null;
let monetaryAmount = null;
let utmSource      = null;
let utmMedium      = null;
let utmCampaign    = null;
let utmContent     = null;

// Dados do card (monetaryAmount + vendedor via responsibleUserId)
try {
  const items = cardResp.items ?? cardResp.data ?? [];
  const list  = Array.isArray(items) ? items : [];
  const card  = list[0];
  if (card?.id) {
    cardId         = card.id;
    cardFound      = true;
    monetaryAmount = card.monetaryAmount ?? card.value ?? null;

    const responsibleUserId = card.responsibleUserId ?? null;
    if (responsibleUserId) {
      const agents = Array.isArray(agentsResp) ? agentsResp : [];
      const agent  = agents.find(a => a.userId === responsibleUserId);
      if (agent) {
        agentEmail = agent.email ?? null;
        agentName  = agent.name  ?? null;
      }
    }
  }
} catch(e) {}

// Dados do contato: nome, telefone e UTMs (via API /core/v1/contact)
try {
  contactName  = contactResp.name ?? null;
  contactPhone = contactResp.phoneNumberFormatted ?? contactResp.phoneNumber?.replace('|', ' ') ?? null;

  const utm = contactResp.utm ?? {};
  utmSource   = utm.source   ?? null;
  utmMedium   = utm.medium   ?? null;
  utmCampaign = utm.campaign ?? null;
  utmContent  = utm.content  ?? utm.headline ?? null;
} catch(e) {}

return [{ json: { ...ctx, cardId, cardFound, agentEmail, agentName, contactName, contactPhone, monetaryAmount, utmSource, utmMedium, utmCampaign, utmContent } }];

const d = $('Extrair Card ID').first().json;

if (!d.sendToDash) {
  return [];
}

const meta = {};
if (d.agentEmail)             meta.crmUserId       = d.agentEmail;
if (d.agentName)              meta.salespersonName = d.agentName;
if (d.contactName)            meta.name            = d.contactName;
if (d.contactPhone)           meta.phone           = d.contactPhone;
if (d.monetaryAmount != null) { meta.value = d.monetaryAmount; meta.currency = 'BRL'; }
if (d.utmSource)   meta.utm_source   = d.utmSource;
if (d.utmMedium)   meta.utm_medium   = d.utmMedium;
if (d.utmCampaign) meta.utm_campaign = d.utmCampaign;
if (d.utmContent)  meta.utm_content  = d.utmContent;

const payload = JSON.stringify({
  event_id:          d.eventId,
  crm_source:        'helena',
  tenant_slug:       'igui',
  store_external_id: d.storeExternalId,
  lead_external_id:  d.contactId,
  to_stage:          d.dashKey,
  occurred_at:       d.occurredAt,
  metadata:          meta
});

return [{ json: { ...d, payload } }];
